func (a *Application) Routes() {
    api := a.Router.Group("/api/v1/") api.GET("/slow", SlowHandler)
}

func SlowHandler(c *gin.Context) {
    // Simulate a slow response time.Sleep(70 * time.Second) c.JSON(http.StatusOK, gin.H{
        "message": "This is a slow response",
    })
}

